1	const PROCESSING_FEE = 5;
2	const COMPONENT_PREMIUM = 25;
3	const COMPONENT_BLOCK_PREMIUM = 60;
4	const COMPONENT_BLOCK_SIZE = 3;
5	const CURSED_SURCHARGE_RATE = 0.5;
6	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
7	const HIGH_ENCHANTMENT_THRESHOLD = 5;
8	
9	const MAIN_ITEM_PREMIUMS: Record<string, number> = {
10	  sword: 100,
11	  amulet: 60,
12	  staff: 80,
13	  potion: 40,
14	};
15	
16	function isComponent(type: string): boolean {
17	  return !(type in MAIN_ITEM_PREMIUMS);
18	}
19	
20	function computeComponentPremium(items: any[]): number {
21	  const componentCounts: Record<string, number> = {};
22	
23	  for (const item of items) {
24	    if (isComponent(item.type)) {
25	      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
26	    }
27	  }
28	
29	  let premium = 0;
30	  for (const count of Object.values(componentCounts)) {
31	    premium += count === COMPONENT_BLOCK_SIZE
32	      ? COMPONENT_BLOCK_PREMIUM
33	      : count * COMPONENT_PREMIUM;
34	  }
35	  return premium;
36	}
37	
38	function computeMainItemPremium(items: any[]): number {
39	  let premium = 0;
40	  for (const item of items) {
41	    if (!isComponent(item.type)) {
42	      const basePremium = MAIN_ITEM_PREMIUMS[item.type];
43	      let itemPremium = basePremium;
44	      if (item.cursed) {
45	        itemPremium += basePremium * CURSED_SURCHARGE_RATE;
46	      }
47	      if (item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD) {
48	        itemPremium += basePremium * HIGH_ENCHANTMENT_SURCHARGE_RATE;
49	      }
50	      premium += itemPremium;
51	    }
52	  }
53	  return premium;
54	}
55	
56	function computeTotalItemPremium(items: any[]): number {
57	  return computeMainItemPremium(items) + computeComponentPremium(items);
58	}
59	
60	function computeMainItemBasePremiumTotal(items: any[]): number {
61	  let total = 0;
62	  for (const item of items) {
63	    if (!isComponent(item.type)) {
64	      total += MAIN_ITEM_PREMIUMS[item.type];
65	    }
66	  }
67	  return total;
68	}
69	
70	function computePolicyBasePremium(items: any[]): number {
71	  return computeMainItemBasePremiumTotal(items) + computeComponentPremium(items);
72	}
73	
74	const FIRST_INSURANCE_RATE = 0.1;
75	const LOYALTY_DISCOUNT_RATE = 0.2;
76	const LOYALTY_THRESHOLD_YEARS = 2;
77	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
78	
79	export function processScenario(scenario: any): any {
80	  const results: any[] = [];
81	  let quoteCount = 0;
82	
83	  for (const step of scenario.steps) {
84	    if (step.op === "quote") {
85	      quoteCount++;
86	      const totalItemPremium = computeTotalItemPremium(step.items);
87	      const policyBase = computePolicyBasePremium(step.items);
88	      let policyModifiers = policyBase * FIRST_INSURANCE_RATE;
89	      if (scenario.customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS) {
90	        policyModifiers -= policyBase * LOYALTY_DISCOUNT_RATE;
91	      }
92	      if (quoteCount > 1) {
93	        policyModifiers -= policyBase * FOLLOW_UP_DISCOUNT_RATE;
94	      }
95	      const premium = Math.ceil(totalItemPremium + policyModifiers + PROCESSING_FEE);
96	      results.push({ premium });
97	    }
98	  }
99	
100	  return { results };
101	}
